import { JIKAN_API_BASE } from '../constants';
import { Anime, Episode } from '../types';

const animeCache = new Map<number, Anime>();

export const getAnimeData = async (malId: number): Promise<Anime> => {
  // Return from cache if available to prevent 429s
  if (animeCache.has(malId)) return animeCache.get(malId)!;

  const fetchWithRetry = async (url: string, retries = 2): Promise<Response> => {
    const response = await fetch(url);
    if (response.status === 429 && retries > 0) {
      // Jikan rate limit hit - wait and retry
      await new Promise(resolve => setTimeout(resolve, 1000));
      return fetchWithRetry(url, retries - 1);
    }
    return response;
  };

  const response = await fetchWithRetry(`${JIKAN_API_BASE}/anime/${malId}`);
  if (!response.ok) {
    throw new Error(`Failed to fetch anime details: ${response.status} ${response.statusText}`);
  }

  const data = await response.json();
  if (!data.data) throw new Error('Invalid response from Jikan API');

  animeCache.set(malId, data.data);
  return data.data;
};

export const searchAnime = async (query: string): Promise<Anime[]> => {
  const response = await fetch(`${JIKAN_API_BASE}/anime?q=${encodeURIComponent(query)}&limit=20`);
  if (!response.ok) throw new Error('Failed to search anime');
  const data = await response.json();
  return data.data;
};

export interface EpisodesResponse {
  data: Episode[];
  pagination: {
    last_visible_page: number;
    has_next_page: boolean;
  };
}

export const getAnimeEpisodes = async (malId: number, page: number = 1): Promise<EpisodesResponse> => {
  const response = await fetch(`${JIKAN_API_BASE}/anime/${malId}/episodes?page=${page}`);
  if (!response.ok) throw new Error('Failed to fetch episodes');
  const data = await response.json();

  return {
    data: data.data.map((ep: any) => ({
      mal_id: ep.mal_id,
      title: ep.title,
      episode_id: ep.mal_id.toString(),
      number: ep.mal_id,
      aired: ep.aired
    })),
    pagination: data.pagination
  };
};

import { SourceResult, SourceType, SourceCategory, AllAnimeSource, Anime } from '../types';
import { getAnimeData } from './jikanService';

const ALLANIME_API = 'https://api.allanime.day/api';
const PROXY = 'https://test.cors.workers.dev/?';

const GQL_SEARCH = `
query($search: SearchInput, $limit: Int, $page: Int, $translationType: String) {
  shows(search: $search, limit: $limit, page: $page, translationType: $translationType) {
    edges {
      node {
        _id
        name
        englishName
      }
    }
  }
}`;

const GQL_EPISODE = `
query($showId: String!, $episodeString: String!, $translationType: String!) {
  episode(showId: $showId, episodeString: $episodeString, translationType: $translationType) {
    sourceUrls
  }
}`;

async function gqlRequest(query: string, variables: any) {
  const response = await fetch(`${PROXY}${encodeURIComponent(ALLANIME_API)}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Origin': 'https://allanime.to',
      'Referer': 'https://allanime.to/'
    },
    body: JSON.stringify({ query, variables })
  });
  const json = await response.json();
  return json.data;
}

export const getAnimeEpisodeSources = async (
  malId: number, 
  episodeNumber: number, 
  category: SourceCategory,
  animeContext?: Anime
): Promise<SourceResult[]> => {
  try {
    // Use context if available to save a Jikan API call
    const anime = animeContext || await getAnimeData(malId);
    const searchName = `${anime.title_english || anime.title} ${anime.year || ''}`.trim();
    const translationType = category === 'dub' ? 'dub' : 'sub';

    const searchData = await gqlRequest(GQL_SEARCH, {
      search: { name: searchName },
      limit: 1,
      translationType
    });

    const show = searchData?.shows?.edges?.[0]?.node;
    if (!show) throw new Error('Anime not found in AllAnime catalog');

    const epData = await gqlRequest(GQL_EPISODE, {
      showId: show._id,
      episodeString: episodeNumber.toString(),
      translationType
    });

    const sources = epData?.episode?.sourceUrls || [];

    return sources.map((src: any) => {
      const isPlayer = src.sourceName.toLowerCase().includes('hls') || src.sourceName.toLowerCase().includes('mp4');

      const rawSource: AllAnimeSource = {
        name: src.sourceName,
        type: isPlayer ? 'player' : 'iframe',
        url: src.sourceUrl
      };

      return {
        url: src.sourceUrl,
        type: isPlayer ? SourceType.DIRECT : SourceType.EMBED,
        provider: 'AllAnime',
        pluginName: src.sourceName,
        label: `${src.sourceName} (${category.toUpperCase()})`,
        category: category,
        rawSource: rawSource
      };
    });
  } catch (error) {
    console.error('AllAnime Bridge Error:', error);
    return [];
  }
};

import { SourcePlugin, SourceType, SourceResult, Anime } from '../types';
import { getAnimeEpisodeSources } from './allAnimeService';

export const resolveSource = async (
  plugin: SourcePlugin,
  malId: number,
  episodeNumber: number,
  animeContext?: Anime
): Promise<SourceResult[]> => {
  // If the plugin is AllAnime, use our bridge service and pass the context
  if (plugin.provider === 'AllAnime') {
    const sources = await getAnimeEpisodeSources(malId, episodeNumber, plugin.category, animeContext);
    if (sources.length > 0) return sources;
  }

  // Fallback/Existing Logic
  if (plugin.type === SourceType.EMBED) {
    const url = (plugin.getVideoUrlTemplate || plugin.url)
      .replace('{animeId}', malId.toString())
      .replace('{episodeNumber}', episodeNumber.toString());

    return [{
      url,
      type: SourceType.EMBED,
      provider: plugin.provider,
      pluginName: plugin.name,
      label: plugin.label,
      category: plugin.category
    }];
  }

  // Demo fallback
  return [{
    url: plugin.url,
    keyUrl: plugin.keyUrl,
    type: SourceType.DIRECT,
    provider: plugin.provider,
    pluginName: plugin.name,
    label: plugin.label,
    category: plugin.category
  }];
};

