  episode(showId: $showId, episodeString: $episodeString, translationType: $translationType) {
    sourceUrls
  }
}`;

async function gqlRequest(query: string, variables: any) {
  const response = await fetch(ALLANIME_API, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Origin': 'https://allanime.to',
      'Referer': 'https://allanime.to/'
    },
    body: JSON.stringify({ query, variables })
  });

  if (!response.ok) {
    throw new Error(`GQL Request Failed: ${response.status}`);
  }

  const json = await response.json();
  return json.data;
}

/**
 * Attempts to find the show using multiple title variations to increase hit rate.
 */
async function findShow(anime: Anime, translationType: string) {
  const searchVariants = [
    anime.title_english,
    anime.title,
    (anime.title_english || anime.title).split(':')[0], // Try part before colon
    (anime.title_english || anime.title).replace(/[^a-zA-Z0-9 ]/g, '') // Stripped alphanumeric
  ].filter((v): v is string => !!v && v.length > 2);

  // Use a Set to ensure unique search attempts
  const uniqueVariants = Array.from(new Set(searchVariants));

  for (const name of uniqueVariants) {
    try {
      const searchData = await gqlRequest(GQL_SEARCH, {
        search: { name },
        limit: 3,
        translationType
      });

      const edges = searchData?.shows?.edges || [];
      if (edges.length > 0) {
        // Find the best match or return first
        return edges[0].node;
      }
    } catch (e) {
      console.warn(`Search attempt failed for variant "${name}":`, e);
    }
  }
  return null;
}

export const getAnimeEpisodeSources = async (
  malId: number, 
  episodeNumber: number, 
  category: SourceCategory,
  animeContext?: Anime
): Promise<SourceResult[]> => {
  try {
    const anime = animeContext || await getAnimeData(malId);
    const translationType = category === 'dub' ? 'dub' : 'sub';

    const show = await findShow(anime, translationType);

    if (!show) {
      throw new Error(`Anime "${anime.title}" not found in AllAnime catalog after multiple attempts.`);
    }

    const epData = await gqlRequest(GQL_EPISODE, {
      showId: show._id,
      episodeString: episodeNumber.toString(),
      translationType
    });

    const sources = epData?.episode?.sourceUrls || [];

    return sources.map((src: any) => {
      const isPlayer = src.sourceName.toLowerCase().includes('hls') || src.sourceName.toLowerCase().includes('mp4');

      const rawSource: AllAnimeSource = {
        name: src.sourceName,
        type: isPlayer ? 'player' : 'iframe',
        url: src.sourceUrl
      };

      return {
        url: src.sourceUrl,
        type: isPlayer ? SourceType.DIRECT : SourceType.EMBED,
        provider: 'AllAnime',
        pluginName: src.sourceName,
        label: `${src.sourceName} (${category.toUpperCase()})`,
        category: category,
        rawSource: rawSource
      };
    });
  } catch (error) {
    console.error('AllAnime Bridge Error:', error);
    return [];
  }
};

import React, { useState, useMemo } from 'react';
